3097 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3098                                                FPClassTest DemandedMask,
3099                                                KnownFPClass &Known,
3100                                                unsigned Depth) {
3101   Use &U = I->getOperandUse(OpNo);
3102   Value *V = U.get();
3103   Type *VTy = V->getType();
3104 
3105   if (DemandedMask == fcNone) {
3106     if (isa<UndefValue>(V))
3107       return false;
3108     replaceUse(U, PoisonValue::get(VTy));
3109     return true;
3110   }
3111 
3112   // Handle constant
3113   Instruction *VInst = dyn_cast<Instruction>(V);
3114   if (!VInst) {
3115     // Handle constants and arguments
3116     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3117 
3118     FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
3119     if (ValidResults == fcNone) {
3120       if (isa<UndefValue>(V))
3121         return false;
3122       replaceUse(U, PoisonValue::get(VTy));
3123       return true;
3124     }
3125 
3126     // Do not try to replace values which are already constants (unless we are
3127     // folding to poison). Doing so could promote poison elements to non-poison
3128     // constants.
3129     if (isa<Constant>(V))
3130       return false;
3131 
3132     Value *FoldedToConst = getFPClassConstant(VTy, ValidResults);
3133     if (!FoldedToConst || FoldedToConst == V)
3134       return false;
3135 
3136     replaceUse(U, FoldedToConst);
3137     return true;
3138   }
3139 
3140   if (Depth == MaxAnalysisRecursionDepth)
3141     return false;
3142 
3143   Value *NewVal;
3144 
3145   if (VInst->hasOneUse()) {
3146     // If the instruction has one use, we can directly simplify it.
3147     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3148   } else {
3149     // If there are multiple uses of this instruction, then we can simplify
3150     // VInst to some other value, but not modify the instruction.
3151     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3152                                                 Depth);
3153   }
3154 
3155   if (!NewVal)
3156     return false;
3157   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3158     salvageDebugInfo(*OpInst);
3159 
3160   replaceUse(U, NewVal);
3161   return true;
3162 }
